use std::io::{stdin};

macro_rules! read {
    ($($t: ty),+) => ({
        let mut a_str = String::new();
        stdin().read_line(&mut a_str).expect("read error");
        let mut a_iter = a_str.split_whitespace();
        (
            $(
            a_iter.next().unwrap().parse::<$t>().expect("parse error"),
            )+
        )
    })
}

fn main() {
	let (k, n, s, p) = read!(i32 , i32 , i32 , i32);
	let x;
    	if n % s != 0 {
        	x = n / s + 1;
    	} else {
        	x = n / s;
    	}
    	let y = x * k;
    	let mut _x;
    	if y % p != 0 {
        	_x = y / p + 1;
    	} else {
        	_x = y / p;
    	}
    	println!("{}" , _x);
}
